ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?name ?region WHERE {
  ?culture a :Culture .
  ?dance a :Dance .
  ?dance p:hasCulture ?culture .
  ?geographical_area a :Geographical_Area .
  ?dance p:hasGeographical_Area ?geographical_area .
  ?dance p:culture_id ?culture_id_g .
  ?culture p:name ?name .
  ?geographical_area p:region ?region .
}
GROUP BY ?culture_id_g ?name ?region }
  component: { SELECT ?name WHERE {
  ?culture a :Culture .
  ?dance a :Dance .
  ?dance p:hasCulture ?culture .
  ?dance p:culture_id ?culture_id_g .
  ?culture p:name ?name .
}
GROUP BY ?culture_id_g ?name }
  component_2: { SELECT ?region WHERE {
  ?geographical_area a :Geographical_Area .
  ?dance a :Dance .
  ?dance p:hasGeographical_Area ?geographical_area .
  ?dance p:culture_id ?culture_id_g .
  ?geographical_area p:region ?region .
}
GROUP BY ?culture_id_g ?region }
}

PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name WHERE {
  ?culture a :Culture .
  ?dance a :Dance .
  ?dance p:hasCulture ?culture .
  ?culture p:name ?name .
  ?dance p:dance_name ?dance_name_f .
  FILTER(STR(?dance_name_f) = "Capoeira")
} }
  component_2: { SELECT ?region WHERE {
  ?geographical_area a :Geographical_Area .
  ?dance a :Dance .
  ?dance p:hasGeographical_Area ?geographical_area .
  ?geographical_area p:region ?region .
  ?dance p:dance_name ?dance_name_f .
  FILTER(STR(?dance_name_f) = "Capoeira")
} }
  full: { SELECT ?name ?region WHERE {
  ?culture a :Culture .
  ?dance a :Dance .
  ?dance p:hasCulture ?culture .
  ?geographical_area a :Geographical_Area .
  ?dance p:hasGeographical_Area ?geographical_area .
  ?culture p:name ?name .
  ?geographical_area p:region ?region .
  ?dance p:dance_name ?dance_name_f .
  FILTER(STR(?dance_name_f) = "Capoeira")
} }
}
